const incoming = $json.body || $json;
const now = new Date().toISOString();
function text(value, fallback = '') { return String(value ?? fallback).trim(); }
function list(value) {
  if (Array.isArray(value)) return value.map((v) => text(v)).filter(Boolean);
  if (typeof value === 'string') return value.split(',').map((v) => text(v)).filter(Boolean);
  return [];
}
function unique(values) { return [...new Set(values.filter(Boolean))]; }
function daysToTimeRange(value) {
  const days = Math.max(1, Math.min(365, Number(value || 30) || 30));
  if (days <= 1) return 'day';
  if (days <= 7) return 'week';
  if (days <= 31) return 'month';
  return 'year';
}
function topicVariants(profile, topic) {
  const variants = profile.queryVariants && typeof profile.queryVariants === 'object' ? profile.queryVariants[topic] : null;
  const fromVariants = Array.isArray(variants) ? variants.map((v) => text(v)).filter(Boolean) : [];
  const fromQuery = text(profile.queries?.[topic]);
  return unique(fromVariants.length ? fromVariants : [fromQuery].filter(Boolean));
}

const profile = {
  userId: text(incoming.userId),
  savedSearchId: text(incoming.savedSearchId),
  logId: text(incoming.logId),
  trigger: text(incoming.trigger, 'manual'),
  country: text(incoming.country, 'India'),
  region: text(incoming.region),
  location: text(incoming.location) || [incoming.country, incoming.region].map((v) => text(v)).filter(Boolean).join(' '),
  category: text(incoming.category, 'Corporate Services'),
  subcategory: text(incoming.subcategory || incoming.sub_category),
  subcategoryOptions: unique(list(incoming.subcategoryOptions || incoming.categoryOptions)),
  topics: unique(list(incoming.topics)).length ? unique(list(incoming.topics)) : ['news', 'govt', 'competitor', 'evergreen'],
  queries: incoming.queries && typeof incoming.queries === 'object' ? incoming.queries : {},
  queryVariants: incoming.queryVariants && typeof incoming.queryVariants === 'object' ? incoming.queryVariants : {},
  preferredDomains: unique(list(incoming.preferredDomains || incoming.includeDomains || incoming.sources)),
  strictSources: Boolean(incoming.strictSources || incoming.strict_sources),
  competitors: unique(list(incoming.competitors)),
  days: Math.max(1, Math.min(365, Number(incoming.days || 30) || 30)),
  targetPerTopic: Math.max(1, Math.min(20, Number(incoming.targetPerTopic || incoming.maxPerTopic || 10) || 10)),
  language: text(incoming.language, 'en'),
  timezone: text(incoming.timezone, 'Asia/Kolkata'),
  callbackUrl: text(incoming.callbackUrl),
  callbackSecret: text(incoming.callbackSecret || incoming.secret),
  startedAt: incoming.startedAt || now
};
if (!profile.userId) throw new Error('userId is required');
if (!profile.callbackUrl) throw new Error('callbackUrl is required');

const allowedTopics = ['news', 'govt', 'competitor', 'evergreen'];
const topicMeta = {
  news: { type: 'news', opportunityType: 'market_news', maxResults: 8, minTavilyScore: 10, searchDepth: 'advanced' },
  govt: { type: 'govt', opportunityType: 'policy', maxResults: 8, minTavilyScore: 10, searchDepth: 'advanced' },
  competitor: { type: 'competitor', opportunityType: 'competitors', maxResults: 6, minTavilyScore: 8, searchDepth: 'advanced' },
  evergreen: { type: 'evergreen', opportunityType: 'evergreen', maxResults: 6, minTavilyScore: 8, searchDepth: 'basic' }
};
const requests = [];
for (const topic of profile.topics) {
  if (!allowedTopics.includes(topic)) continue;
  const meta = topicMeta[topic];
  const variants = topicVariants(profile, topic).slice(0, topic === 'competitor' ? 4 : 8);
  variants.forEach((query, variantIndex) => {
    const tavilyBody = { query, topic: 'news', search_depth: meta.searchDepth, max_results: meta.maxResults, include_answer: false, include_raw_content: false };
    if (topic !== 'evergreen') tavilyBody.time_range = daysToTimeRange(profile.days);
    if (profile.strictSources && profile.preferredDomains.length) tavilyBody.include_domains = profile.preferredDomains;
    requests.push({ json: { profile, topic, variantIndex, type: meta.type, opportunityType: meta.opportunityType, sourceQuery: query, minTavilyScore: Math.max(0, Math.min(100, Number(incoming.minTavilyScore || meta.minTavilyScore) || meta.minTavilyScore)), tavilyBody } });
  });
}
if (!requests.length) throw new Error('No valid topic query variants found. Backend must send queries or queryVariants for selected topics.');
return requests;

function hashString(input) {
  let hash = 2166136261;
  for (let i = 0; i < String(input).length; i += 1) {
    hash ^= String(input).charCodeAt(i);
    hash = Math.imul(hash, 16777619) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
function hostFromUrl(url) {
  const value = String(url || '').trim();
  try { return new URL(value).hostname.replace(/^www\./, ''); }
  catch (_e) {
    const match = value.match(/^https?:\/\/(?:www\.)?([^/]+)/i);
    return match ? match[1].toLowerCase() : 'dynamic-search';
  }
}
const requestItems = $('Build Topic Requests').all();
const out = [];
for (let i = 0; i < $input.all().length; i += 1) {
  const response = $input.all()[i].json || {};
  const request = requestItems[i]?.json || {};
  const profile = request.profile || {};
  const results = Array.isArray(response.results) ? response.results : Array.isArray(response.data?.results) ? response.data.results : [];
  for (const row of results) {
    const title = String(row.title || '').trim();
    const url = String(row.url || '').trim();
    const summary = String(row.content || row.snippet || row.summary || '').trim();
    if (!title || !url) continue;
    const sourceType = hostFromUrl(url);
    const tavilyScore = typeof row.score === 'number' ? Math.round(row.score * 100) : 50;
    if (tavilyScore < (request.minTavilyScore || 0)) continue;
    out.push({ json: {
      userId: profile.userId, savedSearchId: profile.savedSearchId, logId: profile.logId,
      country: profile.country, region: profile.region, location: profile.location, language: profile.language,
      type: request.type, topic: request.topic, variantIndex: request.variantIndex, opportunityType: request.opportunityType,
      category: profile.category, subcategory: profile.subcategory, subcategoryOptions: profile.subcategoryOptions || [], competitors: profile.competitors || [], days: profile.days,
      title: title.slice(0, 500), summary: summary.slice(0, 1400), aiSummary: summary.slice(0, 1400),
      tavilyScore, relevanceScore: tavilyScore, relevance_reason: 'Tavily relevance score ' + tavilyScore + ' for ' + request.topic + ' query variant ' + request.variantIndex + '.',
      url, urlHash: hashString(url.toLowerCase().replace(/\/$/, '')), source: sourceType, sourceId: sourceType, sourceType, sourceQuery: request.sourceQuery,
      fetched_at: new Date().toISOString(), publishedAt: row.published_date || row.publishedAt || new Date().toISOString()
    } });
  }
}
return out.length ? out : [{ json: { _skip: true } }];

